const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');
const functions = require('@google-cloud/functions-framework');

// Environment variables for credentials
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER;

// Initialize SendGrid
sgMail.setApiKey(SENDGRID_API_KEY);

// Initialize Twilio
const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

functions.http('sendNotification', async (req, res) => {
  try {
    const { email, subject, text, phoneNumber, smsMessage } = req.body;

    // Send email via SendGrid
    const emailResponse = await sgMail.send({
      to: email,
      from: 'your-email@example.com',
      subject: subject,
      text: text,
    });

    // Send SMS via Twilio
    const smsResponse = await twilioClient.messages.create({
      body: smsMessage,
      from: TWILIO_PHONE_NUMBER,
      to: phoneNumber,
    });

    res.status(200).send({
      emailStatus: emailResponse[0].statusCode,
      smsStatus: smsResponse.status,
    });
  } catch (error) {
    console.error('Error sending notification:', error);
    res.status(500).send('Error sending notification');
  }
});